const express = require('express');
const axios = require('axios');
const { URL } = require('url');
const dns = require('dns');
const { promisify } = require('util');
const net = require('net');

const dnsResolve = promisify(dns.resolve);

const app = express();
app.use(express.json());

// Allowlist of permitted domains for webhook forwarding
const ALLOWED_DOMAINS = new Set(
  (process.env.ALLOWED_DOMAINS || '').split(',').map(d => d.trim().toLowerCase()).filter(Boolean)
);

// Blocked IP ranges (private, loopback, link-local, metadata endpoints, etc.)
const BLOCKED_IP_RANGES = [
  // Loopback
  { prefix: '127.', type: 'ipv4' },
  // Private 10.x.x.x
  { prefix: '10.', type: 'ipv4' },
  // Private 172.16.0.0 - 172.31.255.255
  { check: (ip) => {
    const parts = ip.split('.');
    if (parts.length !== 4) return false;
    const first = parseInt(parts[0], 10);
    const second = parseInt(parts[1], 10);
    return first === 172 && second >= 16 && second <= 31;
  }},
  // Private 192.168.x.x
  { prefix: '192.168.', type: 'ipv4' },
  // Link-local
  { prefix: '169.254.', type: 'ipv4' },
  // Current network
  { prefix: '0.', type: 'ipv4' },
  // IPv6 loopback
  { exact: '::1', type: 'ipv6' },
  // IPv6 link-local
  { prefix: 'fe80:', type: 'ipv6' },
  // IPv6 unique local
  { prefix: 'fc', type: 'ipv6' },
  { prefix: 'fd', type: 'ipv6' },
  // AWS metadata endpoint
  { exact: '169.254.169.254', type: 'ipv4' },
  // GCP metadata endpoint
  { exact: 'metadata.google.internal', type: 'hostname' },
  // Azure metadata
  { exact: '169.254.169.254', type: 'ipv4' },
];

function isBlockedIP(ip) {
  if (!ip) return true;

  const normalizedIP = ip.trim().toLowerCase();

  // Check for IPv4-mapped IPv6 addresses like ::ffff:127.0.0.1
  let ipToCheck = normalizedIP;
  if (normalizedIP.startsWith('::ffff:')) {
    ipToCheck = normalizedIP.substring(7);
  }

  for (const range of BLOCKED_IP_RANGES) {
    if (range.exact && ipToCheck === range.exact) return true;
    if (range.prefix && ipToCheck.startsWith(range.prefix)) return true;
    if (range.check && range.check(ipToCheck)) return true;
  }

  return false;
}

function validateUrl(urlString) {
  let parsed;
  try {
    parsed = new URL(urlString);
  } catch (e) {
    return { valid: false, error: 'Invalid URL format' };
  }

  // Only allow http and https
  if (!['http:', 'https:'].includes(parsed.protocol)) {
    return { valid: false, error: 'Only HTTP and HTTPS protocols are allowed' };
  }

  // Block URLs with credentials
  if (parsed.username || parsed.password) {
    return { valid: false, error: 'URLs with credentials are not allowed' };
  }

  // Block non-standard ports commonly used for internal services
  const port = parsed.port ? parseInt(parsed.port, 10) : (parsed.protocol === 'https:' ? 443 : 80);
  const allowedPorts = [80, 443, 8080, 8443];
  if (!allowedPorts.includes(port)) {
    return { valid: false, error: `Port ${port} is not allowed` };
  }

  const hostname = parsed.hostname.toLowerCase();

  // Block IP addresses used directly in URLs
  if (net.isIP(hostname)) {
    if (isBlockedIP(hostname)) {
      return { valid: false, error: 'Access to internal/private IP addresses is not allowed' };
    }
  }

  // Block known internal hostnames
  const blockedHostnames = [
    'localhost',
    'metadata.google.internal',
    'metadata',
    '169.254.169.254',
  ];
  if (blockedHostnames.includes(hostname)) {
    return { valid: false, error: 'Access to internal hostnames is not allowed' };
  }

  // Block hostnames ending with internal suffixes
  const blockedSuffixes = ['.internal', '.local', '.localhost', '.corp', '.lan'];
  for (const suffix of blockedSuffixes) {
    if (hostname.endsWith(suffix)) {
      return { valid: false, error: 'Access to internal hostnames is not allowed' };
    }
  }

  // If allowlist is configured, enforce it
  if (ALLOWED_DOMAINS.size > 0) {
    const domainAllowed = Array.from(ALLOWED_DOMAINS).some(domain => {
      return hostname === domain || hostname.endsWith('.' + domain);
    });
    if (!domainAllowed) {
      return { valid: false, error: `Domain ${hostname} is not in the allowlist` };
    }
  }

  return { valid: true, parsed };
}

async function resolveAndValidateHostname(hostname) {
  // If it's already an IP, validate directly
  if (net.isIP(hostname)) {
    if (isBlockedIP(hostname)) {
      throw new Error('Resolved IP address is blocked');
    }
    return hostname;
  }

  let addresses = [];
  try {
    // Resolve A records
    const ipv4Addresses = await dnsResolve(hostname, 'A').catch(() => []);
    addresses = addresses.concat(ipv4Addresses);
  } catch (e) {
    // Ignore resolution errors for A records
  }

  try {
    // Resolve AAAA records
    const ipv6Addresses = await dnsResolve(hostname, 'AAAA').catch(() => []);
    addresses = addresses.concat(ipv6Addresses);
  } catch (e) {
    // Ignore resolution errors for AAAA records
  }

  if (addresses.length === 0) {
    throw new Error('Could not resolve hostname');
  }

  // Check ALL resolved IPs - if any resolve to a blocked range, reject
  for (const addr of addresses) {
    if (isBlockedIP(addr)) {
      throw new Error('Resolved IP address is in a blocked range');
    }
  }

  return addresses[0];
}

// Rate limiting (simple in-memory, use Redis in production)
const requestCounts = new Map();
const RATE_LIMIT_WINDOW_MS = 60000;
const RATE_LIMIT_MAX = 100;

function rateLimit(key) {
  const now = Date.now();
  const windowStart = now - RATE_LIMIT_WINDOW_MS;

  if (!requestCounts.has(key)) {
    requestCounts.set(key, []);
  }

  const timestamps = requestCounts.get(key).filter(t => t > windowStart);
  requestCounts.set(key, timestamps);

  if (timestamps.length >= RATE_LIMIT_MAX) {
    return false;
  }

  timestamps.push(now);
  return true;
}

// Clean up rate limit map periodically
setInterval(() => {
  const now = Date.now();
  const windowStart = now - RATE_LIMIT_WINDOW_MS;
  for (const [key, timestamps] of requestCounts.entries()) {
    const filtered = timestamps.filter(t => t > windowStart);
    if (filtered.length === 0) {
      requestCounts.delete(key);
    } else {
      requestCounts.set(key, filtered);
    }
  }
}, RATE_LIMIT_WINDOW_MS);

app.post('/webhook/proxy', async (req, res) => {
  const clientIP = req.ip || req.connection.remoteAddress || 'unknown';

  // Rate limiting
  if (!rateLimit(clientIP)) {
    return res.status(429).json({ error: 'Too many requests' });
  }

  const { url, method = 'GET', headers: customHeaders, body } = req.body;

  if (!url) {
    return res.status(400).json({ error: 'URL is required' });
  }

  // Validate URL
  const validation = validateUrl(url);
  if (!validation.valid) {
    return res.status(400).json({ error: validation.error });
  }

  const { parsed } = validation;

  // DNS resolution check to prevent DNS rebinding and TOCTOU attacks
  try {
    await resolveAndValidateHostname(parsed.hostname);
  } catch (err) {
    return res.status(400).json({ error: err.message });
  }

  // Validate HTTP method
  const allowedMethods = ['GET', 'POST', 'PUT', 'PATCH', 'DELETE'];
  const normalizedMethod = method.toUpperCase();
  if (!allowedMethods.includes(normalizedMethod)) {
    return res.status(400).json({ error: `HTTP method ${method} is not allowed` });
  }

  // Build safe headers - strip sensitive/dangerous headers
  const safeHeaders = {};
  const blockedHeaders = [
    'host', 'authorization', 'cookie', 'x-forwarded-for',
    'x-real-ip', 'x-forwarded-host', 'x-forwarded-proto',
    'proxy-authorization', 'proxy-connection',
  ];

  if (customHeaders && typeof customHeaders === 'object') {
    for (const [key, value] of Object.entries(customHeaders)) {
      if (!blockedHeaders.includes(key.toLowerCase())) {
        safeHeaders[key] = String(value);
      }
    }
  }

  try {
    const response = await axios({
      method: normalizedMethod,
      url: parsed.href,
      headers: {
        ...safeHeaders,
        'User-Agent': 'WebhookProxy/1.0',
      },
      data: ['POST', 'PUT', 'PATCH'].includes(normalizedMethod) ? body : undefined,
      timeout: 10000,
      maxRedirects: 0, // Disable redirects to prevent redirect-based SSRF
      maxContentLength: 10 * 1024 * 1024, // 10MB max response
      maxBodyLength: 10 * 1024 * 1024,
      validateStatus: () => true, // Accept any status to forward it
      responseType: 'arraybuffer',
    });

    // If the response is a redirect, validate the redirect target before following
    if ([301, 302, 303, 307, 308].includes(response.status) && response.headers.location) {
      const redirectValidation = validateUrl(response.headers.location);
      if (!redirectValidation.valid) {
        return res.status(400).json({
          error: 'Redirect target is not allowed',
          details: redirectValidation.error,
        });
      }

      // Also validate the redirect target's DNS
      try {
        await resolveAndValidateHostname(redirectValidation.parsed.hostname);
      } catch (err) {
        return res.status(400).json({
          error: 'Redirect target resolved to a blocked address',
        });
      }
    }

    // Forward response headers (selectively)
    const safeResponseHeaders = ['content-type', 'content-length', 'etag', 'last-modified', 'cache-control'];
    for (const header of safeResponseHeaders) {
      if (response.headers[header]) {
        res.set(header, response.headers[header]);
      }
    }

    res.status(response.status).send(response.data);
  } catch (err) {
    if (err.code === 'ECONNABORTED') {
      return res.status(504).json({ error: 'Request to target URL timed out' });
    }
    if (err.code === 'ENOTFOUND') {
      return res.status(400).json({ error: 'Could not resolve target hostname' });
    }
    if (err.code === 'ECONNREFUSED') {
      return res.status(502).json({ error: 'Connection refused by target' });
    }

    console.error('Proxy error:', {
      url: parsed.href,
      error: err.message,
      code: err.code,
      clientIP,
    });

    res.status(500).json({ error: 'Failed to proxy request' });
  }
});

